@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <a href="/patients/new" class="btn btn-primary">Add Patient</a>
    </div>
</div>

@if (pets == null)
{
    <p>Loading...</p>
}
else if (!pets.Any())
{
    <p>No patients found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pet in pets)
            {
                <tr>
                    <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                    <td>
                        <a href="/patients/@pet.Id/edit" class="btn btn-sm btn-outline-secondary">Edit</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private string searchTerm = "";

    protected override async Task OnInitializedAsync()
    {
        await LoadPets();
    }

    private async Task LoadPets()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Owner.FirstName.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        pets = await query.OrderBy(p => p.Name).ToListAsync();
    }

    private async Task Search() => await LoadPets();
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Patient Details</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <h1>@pet.Name</h1>
    <p><strong>Species:</strong> @pet.Species | <strong>Breed:</strong> @pet.Breed | <strong>Weight:</strong> @pet.Weight kg</p>
    <p><strong>Date of Birth:</strong> @pet.DateOfBirth.ToShortDateString()</p>
    <p><strong>Owner:</strong> @pet.Owner.FirstName @pet.Owner.LastName (@pet.Owner.Phone, @pet.Owner.Email)</p>

    <a href="/patients/@pet.Id/edit" class="btn btn-outline-secondary mb-3">Edit</a>

    <h3>Treatment Notes</h3>
    <button class="btn btn-sm btn-primary mb-2" @onclick="ShowAddNote">Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3 p-3">
            <EditForm Model="noteModel" OnValidSubmit="SaveNote" FormName="noteForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="noteModel.Date" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="noteModel.VeterinarianName" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <InputTextArea class="form-control" @bind-Value="noteModel.Description" />
                </div>
                <div class="row mb-2">
                    <div class="col-md-6">
                        <label class="form-label">Diagnosis</label>
                        <InputText class="form-control" @bind-Value="noteModel.Diagnosis" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Medication</label>
                        <InputText class="form-control" @bind-Value="noteModel.Medication" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Save</button>
                <button type="button" class="btn btn-secondary" @onclick="() => showNoteForm = false">Cancel</button>
            </EditForm>
        </div>
    }

    @if (pet.TreatmentNotes.Any())
    {
        <table class="table table-sm">
            <thead>
                <tr><th>Date</th><th>Vet</th><th>Diagnosis</th><th>Medication</th><th>Description</th></tr>
            </thead>
            <tbody>
                @foreach (var note in pet.TreatmentNotes.OrderByDescending(n => n.Date))
                {
                    <tr>
                        <td>@note.Date.ToShortDateString()</td>
                        <td>@note.VeterinarianName</td>
                        <td>@note.Diagnosis</td>
                        <td>@note.Medication</td>
                        <td>@note.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p>No treatment notes yet.</p>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private TreatmentNoteModel noteModel = new();

    private class TreatmentNoteModel
    {
        public DateTime Date { get; set; } = DateTime.Today;
        public string Description { get; set; } = "";
        public string Diagnosis { get; set; } = "";
        public string Medication { get; set; } = "";
        public string VeterinarianName { get; set; } = "";
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pet = await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes)
            .FirstOrDefaultAsync(p => p.Id == Id);
    }

    private void ShowAddNote()
    {
        noteModel = new TreatmentNoteModel { Date = DateTime.Today };
        showNoteForm = true;
    }

    private async Task SaveNote()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var note = new TreatmentNote
        {
            PetId = Id,
            Date = noteModel.Date,
            Description = noteModel.Description,
            Diagnosis = noteModel.Diagnosis,
            Medication = noteModel.Medication,
            VeterinarianName = noteModel.VeterinarianName
        };
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
        showNoteForm = false;
        await LoadPet();
        StateHasChanged();
    }
}

