@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = new();
    private List<Owner> owners = new();
    private List<Payment> payments = new();
    private bool showPayment;
    private int paymentInvoiceId;
    private PaymentFormModel paymentModel = new();
    private InvoiceFormModel invoiceModel = new();

    private class PaymentFormModel
    {
        public decimal Amount { get; set; }
        public string Method { get; set; } = "Cash";
        public DateTime PaymentDate { get; set; } = DateTime.Today;
    }

    private class LineItemModel
    {
        public string Description { get; set; } = "";
        public decimal Amount { get; set; }
        public int Quantity { get; set; } = 1;
    }

    private class InvoiceFormModel
    {
        public int OwnerId { get; set; }
        public DateTime IssuedDate { get; set; } = DateTime.Today;
        public DateTime DueDate { get; set; } = DateTime.Today.AddDays(30);
        public List<LineItemModel> LineItems { get; set; } = new() { new LineItemModel() };
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices.Include(i => i.Owner).Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
        payments = await db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.PaymentDate).ToListAsync();
    }

    private void AddLineItem()
    {
        invoiceModel.LineItems.Add(new LineItemModel());
    }

    private async Task CreateInvoice()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var invoice = new Invoice
        {
            OwnerId = invoiceModel.OwnerId,
            IssuedDate = invoiceModel.IssuedDate,
            DueDate = invoiceModel.DueDate,
            TotalAmount = invoiceModel.LineItems.Sum(li => li.Amount * li.Quantity),
            Status = InvoiceStatus.Pending,
            LineItems = invoiceModel.LineItems.Select(li => new InvoiceLineItem
            {
                Description = li.Description,
                Amount = li.Amount,
                Quantity = li.Quantity
            }).ToList()
        };
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        invoiceModel = new InvoiceFormModel();
        activeTab = "invoices";
        await LoadData();
        StateHasChanged();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        paymentInvoiceId = inv.Id;
        paymentModel = new PaymentFormModel { Amount = inv.TotalAmount - inv.Payments.Sum(p => p.Amount) };
        showPayment = true;
    }

    private async Task ProcessPayment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(new Payment
        {
            InvoiceId = paymentInvoiceId,
            Amount = paymentModel.Amount,
            Method = paymentModel.Method,
            PaymentDate = paymentModel.PaymentDate
        });

        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == paymentInvoiceId);
        var totalPaid = invoice.Payments.Sum(p => p.Amount) + paymentModel.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
        showPayment = false;
        await LoadData();
        StateHasChanged();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

