@@ -1,0 +1,253 @@
+@page "/appointments"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@inject IDbContextFactory<ApplicationDbContext> DbFactory
+
+<PageTitle>Appointments</PageTitle>
+
+<h1>Appointments</h1>
+
+<div class="d-flex justify-content-between align-items-center mb-3">
+    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous</button>
+    <h5>@weekStart.ToString("MMM dd") - @weekStart.AddDays(6).ToString("MMM dd, yyyy")</h5>
+    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
+</div>
+
+<div class="table-responsive">
+    <table class="table table-bordered table-sm">
+        <thead>
+            <tr>
+                <th style="width:80px">Time</th>
+                @for (int d = 0; d < 7; d++)
+                {
+                    var day = weekStart.AddDays(d);
+                    <th>@day.ToString("ddd MM/dd")</th>
+                }
+            </tr>
+        </thead>
+        <tbody>
+            @for (int hour = 8; hour < 18; hour++)
+            {
+                <tr>
+                    <td><strong>@hour:00</strong></td>
+                    @for (int d = 0; d < 7; d++)
+                    {
+                        var slotDate = weekStart.AddDays(d);
+                        var slotTime = new DateTime(slotDate.Year, slotDate.Month, slotDate.Day, hour, 0, 0);
+                        var appt = GetAppointmentAt(slotTime);
+                        if (appt != null)
+                        {
+                            <td class="table-info" style="cursor:pointer" @onclick="() => EditAppointment(appt)">
+                                <small><strong>@appt.Pet.Name</strong><br/>@appt.Reason</small>
+                            </td>
+                        }
+                        else
+                        {
+                            <td style="cursor:pointer" @onclick="() => CreateAtSlot(slotTime)">
+                                &nbsp;
+                            </td>
+                        }
+                    }
+                </tr>
+            }
+        </tbody>
+    </table>
+</div>
+
+@if (showForm)
+{
+    <div class="modal d-block" tabindex="-1" style="background-color:rgba(0,0,0,0.5)">
+        <div class="modal-dialog">
+            <div class="modal-content">
+                <div class="modal-header">
+                    <h5 class="modal-title">@(editingId > 0 ? "Edit Appointment" : "New Appointment")</h5>
+                    <button type="button" class="btn-close" @onclick="CloseForm"></button>
+                </div>
+                <EditForm Model="formModel" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
+                    <DataAnnotationsValidator />
+                    <div class="modal-body">
+                        <ValidationSummary />
+                        <div class="mb-2">
+                            <label class="form-label">Pet</label>
+                            <InputSelect class="form-select" @bind-Value="formModel.PetId">
+                                <option value="0">-- Select Pet --</option>
+                                @foreach (var p in allPets)
+                                {
+                                    <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
+                                }
+                            </InputSelect>
+                        </div>
+                        <div class="row mb-2">
+                            <div class="col-md-6">
+                                <label class="form-label">Start</label>
+                                <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="formModel.StartTime" />
+                            </div>
+                            <div class="col-md-6">
+                                <label class="form-label">End</label>
+                                <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="formModel.EndTime" />
+                            </div>
+                        </div>
+                        <div class="mb-2">
+                            <label class="form-label">Reason</label>
+                            <InputText class="form-control" @bind-Value="formModel.Reason" />
+                        </div>
+                        <div class="mb-2">
+                            <label class="form-label">Notes</label>
+                            <InputTextArea class="form-control" @bind-Value="formModel.Notes" />
+                        </div>
+                        @if (editingId > 0)
+                        {
+                            <div class="mb-2">
+                                <label class="form-label">Status</label>
+                                <InputSelect class="form-select" @bind-Value="formModel.Status">
+                                    @foreach (var s in Enum.GetValues<AppointmentStatus>())
+                                    {
+                                        <option value="@s">@s</option>
+                                    }
+                                </InputSelect>
+                            </div>
+                        }
+                    </div>
+                    <div class="modal-footer">
+                        @if (editingId > 0)
+                        {
+                            <button type="button" class="btn btn-danger me-auto" @onclick="CancelAppointment">Cancel Appointment</button>
+                        }
+                        <button type="button" class="btn btn-secondary" @onclick="CloseForm">Close</button>
+                        <button type="submit" class="btn btn-primary">Save</button>
+                    </div>
+                </EditForm>
+            </div>
+        </div>
+    </div>
+}
+
+@code {
+    private DateTime weekStart;
+    private List<Appointment> appointments = new();
+    private List<Pet> allPets = new();
+    private bool showForm;
+    private int editingId;
+    private AppointmentFormModel formModel = new();
+
+    private class AppointmentFormModel
+    {
+        public int PetId { get; set; }
+        public DateTime StartTime { get; set; }
+        public DateTime EndTime { get; set; }
+        public string Reason { get; set; } = "";
+        public string Notes { get; set; } = "";
+        public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;
+    }
+
+    protected override async Task OnInitializedAsync()
+    {
+        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
+        await LoadData();
+    }
+
+    private async Task LoadData()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var weekEnd = weekStart.AddDays(7);
+        appointments = await db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd && a.Status != AppointmentStatus.Cancelled)
+            .ToListAsync();
+        allPets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
+    }
+
+    private Appointment? GetAppointmentAt(DateTime slotTime)
+    {
+        return appointments.FirstOrDefault(a => a.StartTime <= slotTime && a.EndTime > slotTime);
+    }
+
+    private void CreateAtSlot(DateTime slotTime)
+    {
+        editingId = 0;
+        formModel = new AppointmentFormModel
+        {
+            StartTime = slotTime,
+            EndTime = slotTime.AddHours(1)
+        };
+        showForm = true;
+    }
+
+    private void EditAppointment(Appointment appt)
+    {
+        editingId = appt.Id;
+        formModel = new AppointmentFormModel
+        {
+            PetId = appt.PetId,
+            StartTime = appt.StartTime,
+            EndTime = appt.EndTime,
+            Reason = appt.Reason,
+            Notes = appt.Notes,
+            Status = appt.Status
+        };
+        showForm = true;
+    }
+
+    private async Task SaveAppointment()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        if (editingId > 0)
+        {
+            var appt = await db.Appointments.FindAsync(editingId);
+            if (appt != null)
+            {
+                appt.PetId = formModel.PetId;
+                appt.StartTime = formModel.StartTime;
+                appt.EndTime = formModel.EndTime;
+                appt.Reason = formModel.Reason;
+                appt.Notes = formModel.Notes;
+                appt.Status = formModel.Status;
+            }
+        }
+        else
+        {
+            db.Appointments.Add(new Appointment
+            {
+                PetId = formModel.PetId,
+                StartTime = formModel.StartTime,
+                EndTime = formModel.EndTime,
+                Reason = formModel.Reason,
+                Notes = formModel.Notes,
+                Status = AppointmentStatus.Scheduled
+            });
+        }
+        await db.SaveChangesAsync();
+        showForm = false;
+        await LoadData();
+        StateHasChanged();
+    }
+
+    private async Task CancelAppointment()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var appt = await db.Appointments.FindAsync(editingId);
+        if (appt != null)
+        {
+            appt.Status = AppointmentStatus.Cancelled;
+            await db.SaveChangesAsync();
+        }
+        showForm = false;
+        await LoadData();
+        StateHasChanged();
+    }
+
+    private void CloseForm() => showForm = false;
+
+    private async Task PreviousWeek()
+    {
+        weekStart = weekStart.AddDays(-7);
+        await LoadData();
+    }
+
+    private async Task NextWeek()
+    {
+        weekStart = weekStart.AddDays(7);
+        await LoadData();
+    }
+}
+

